import { render, screen, fireEvent } from '@testing-library/react';
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';

vi.mock('../../../../src/webview/components/ui/overlay/tooltip', async () => {
  const React = await import('react');

  function TooltipProvider({ children }: React.PropsWithChildren): React.ReactElement {
    return <>{children}</>;
  }

  function Tooltip({ children }: React.PropsWithChildren): React.ReactElement {
    return <>{children}</>;
  }

  function TooltipTrigger({
    asChild: _asChild,
    children,
  }: React.PropsWithChildren<{ asChild?: boolean }>): React.ReactElement {
    return React.Children.only(children) as React.ReactElement;
  }

  function TooltipContent({
    children,
    ...props
  }: React.PropsWithChildren<Record<string, unknown>>): React.ReactElement {
    return (
      <div role="tooltip" {...props}>
        {children}
      </div>
    );
  }

  return { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger };
});

import { DagModeToggle } from '../../../../src/webview/components/toolbar/DagModeToggle';
import { graphStore } from '../../../../src/webview/store/state';
import { clearSentMessages, findMessage } from '../../../helpers/sentMessages';

function setDefaultState(dagMode: 'radialout' | 'td' | 'lr' | null = null): void {
  graphStore.setState({ dagMode });
}

describe('toolbar/DagModeToggle', () => {
  beforeEach(() => {
    clearSentMessages();
    setDefaultState();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('renders every DAG mode button with its tooltip label', () => {
    render(<DagModeToggle />);

    const buttons = screen.getAllByRole('button');
    const tooltips = screen.getAllByRole('tooltip');

    expect(buttons).toHaveLength(4);
    expect(tooltips.map(node => node.textContent)).toEqual([
      'Default',
      'Radial Out',
      'Top Down',
      'Left to Right',
    ]);
    buttons.forEach(button => {
      expect(button).toHaveClass('h-7', 'w-7');
    });
  });

  it('marks only the active DAG mode button as default', () => {
    setDefaultState('td');

    render(<DagModeToggle />);

    const buttons = screen.getAllByRole('button');

    expect(buttons[0]).toHaveClass('hover:bg-accent');
    expect(buttons[1]).toHaveClass('hover:bg-accent');
    expect(buttons[2]).not.toHaveClass('hover:bg-accent');
    expect(buttons[3]).toHaveClass('hover:bg-accent');
  });

  it('posts the selected DAG mode when a non-default option is clicked', () => {
    render(<DagModeToggle />);

    fireEvent.click(screen.getAllByRole('button')[1]);

    expect(findMessage('UPDATE_DAG_MODE')).toEqual({
      payload: { dagMode: 'radialout' },
      type: 'UPDATE_DAG_MODE',
    });
  });

  it('posts a null DAG mode when the default option is clicked', () => {
    setDefaultState('lr');

    render(<DagModeToggle />);

    fireEvent.click(screen.getAllByRole('button')[0]);

    expect(findMessage('UPDATE_DAG_MODE')).toEqual({
      payload: { dagMode: null },
      type: 'UPDATE_DAG_MODE',
    });
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import { SearchBar } from '../../../../src/webview/components/searchBar/Field';
import type { SearchOptions } from '../../../../src/webview/components/searchBar/field/model';

describe('SearchBar (mutation targets)', () => {
  const defaultOptions: SearchOptions = {
    matchCase: false,
    wholeWord: false,
    regex: false,
  };

  const mockOnChange = vi.fn();
  const mockOnOptionsChange = vi.fn();

  beforeEach(() => {
    vi.clearAllMocks();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('uses default placeholder when not specified', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    expect(screen.getByPlaceholderText('Search files...')).toBeInTheDocument();
  });

  it('uses custom placeholder when specified', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
        placeholder="Custom..."
      />
    );
    expect(screen.getByPlaceholderText('Custom...')).toBeInTheDocument();
  });

  it('applies custom className', () => {
    const { container } = render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
        className="my-custom-class"
      />
    );
    expect(container.firstElementChild?.className).toContain('my-custom-class');
  });

  it('does not show results when value is empty', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
        resultCount={5}
        totalCount={100}
      />
    );
    expect(screen.queryByText('5 of 100')).not.toBeInTheDocument();
  });

  it('does not show results when resultCount is undefined', () => {
    render(
      <SearchBar
        value="test"
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
        totalCount={100}
      />
    );
    expect(screen.queryByText(/of 100/)).not.toBeInTheDocument();
  });

  it('does not show results when totalCount is undefined', () => {
    render(
      <SearchBar
        value="test"
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
        resultCount={5}
      />
    );
    expect(screen.queryByText(/5 of/)).not.toBeInTheDocument();
  });

  it('shows results when value, resultCount, and totalCount are all provided', () => {
    render(
      <SearchBar
        value="test"
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
        resultCount={3}
        totalCount={50}
      />
    );
    expect(screen.getByText('3 of 50')).toBeInTheDocument();
  });

  it('applies error border class when regexError is set', () => {
    render(
      <SearchBar
        value="test["
        onChange={mockOnChange}
        options={{ ...defaultOptions, regex: true }}
        onOptionsChange={mockOnOptionsChange}
        regexError="Invalid regex"
        resultCount={0}
        totalCount={10}
      />
    );
    const input = screen.getByRole('textbox');
    expect(input.className).toContain('inputValidation-errorBorder');
  });

  it('applies normal border class when no regex error', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    const input = screen.getByRole('textbox');
    expect(input.className).not.toContain('inputValidation-errorBorder');
  });

  it('does not show clear button when value is empty', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    expect(screen.queryByTitle('Clear search (Escape)')).not.toBeInTheDocument();
  });

  it('shows clear button when value is non-empty', () => {
    render(
      <SearchBar
        value="test"
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    expect(screen.getByTitle('Clear search (Escape)')).toBeInTheDocument();
  });

  it('passes hasError to regex toggle button when regexError is set', () => {
    render(
      <SearchBar
        value="test["
        onChange={mockOnChange}
        options={{ ...defaultOptions, regex: true }}
        onOptionsChange={mockOnOptionsChange}
        regexError="bad regex"
      />
    );
    const regexButton = screen.getByTitle('Use Regular Expression (Alt+R)');
    expect(regexButton.className).toContain('errorBackground');
  });

  it('does not pass hasError to regex toggle when no regex error', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={{ ...defaultOptions, regex: true }}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    const regexButton = screen.getByTitle('Use Regular Expression (Alt+R)');
    expect(regexButton.className).not.toContain('errorBackground');
  });

  it('toggles matchCase option from true to false', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={{ matchCase: true, wholeWord: false, regex: false }}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    fireEvent.click(screen.getByTitle('Match Case (Alt+C)'));
    expect(mockOnOptionsChange).toHaveBeenCalledWith({
      matchCase: false,
      wholeWord: false,
      regex: false,
    });
  });

  it('passes onChange value from input change event', () => {
    render(
      <SearchBar
        value=""
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    const input = screen.getByRole('textbox');
    fireEvent.change(input, { target: { value: 'hello world' } });
    expect(mockOnChange).toHaveBeenCalledWith('hello world');
  });

  it('renders input with the current value', () => {
    render(
      <SearchBar
        value="existing text"
        onChange={mockOnChange}
        options={defaultOptions}
        onOptionsChange={mockOnOptionsChange}
      />
    );
    expect(screen.getByDisplayValue('existing text')).toBeInTheDocument();
  });
});

