import { act, renderHook } from '@testing-library/react';
import { describe, expect, it, vi } from 'vitest';
import {
  PLUGIN_OVERLAY_RENDERER_ERROR,
  getPluginOverlayRegistrations,
  renderPluginOverlayRegistrations,
  usePluginOverlays,
} from '../../../../src/webview/components/graph/runtime/pluginOverlays';

describe('usePluginOverlays', () => {
  it('returns an empty overlay list when no plugin host is available', () => {
    expect(getPluginOverlayRegistrations(undefined)).toEqual([]);
  });

  it('returns the plugin host overlay registrations when a host is available', () => {
    const overlays = [{ id: 'badge', fn: vi.fn() }];
    const pluginHost = {
      getOverlays: vi.fn(() => overlays),
    } as unknown as NonNullable<Parameters<typeof usePluginOverlays>[0]>;

    expect(getPluginOverlayRegistrations(pluginHost)).toBe(overlays);
    expect(pluginHost.getOverlays).toHaveBeenCalledOnce();
  });

  it('renders all overlay registrations with the computed canvas context', () => {
    const firstOverlay = vi.fn();
    const secondOverlay = vi.fn();
    const ctx = {
      canvas: { height: 180, width: 320 },
    } as CanvasRenderingContext2D;

    renderPluginOverlayRegistrations({
      ctx,
      globalScale: 2.5,
      overlays: [
        { id: 'first', fn: firstOverlay },
        { id: 'second', fn: secondOverlay },
      ],
    });

    expect(firstOverlay).toHaveBeenCalledWith({
      ctx,
      globalScale: 2.5,
      height: 180,
      width: 320,
    });
    expect(secondOverlay).toHaveBeenCalledWith({
      ctx,
      globalScale: 2.5,
      height: 180,
      width: 320,
    });
  });

  it('logs overlay errors and keeps processing direct registrations', () => {
    const onError = vi.fn();
    const goodOverlay = vi.fn();
    const thrownError = new Error('boom');

    renderPluginOverlayRegistrations({
      ctx: { canvas: { height: 90, width: 120 } } as CanvasRenderingContext2D,
      globalScale: 1,
      onError,
      overlays: [
        { id: 'bad', fn: () => { throw thrownError; } },
        { id: 'good', fn: goodOverlay },
      ],
    });

    expect(onError).toHaveBeenCalledOnce();
    expect(onError).toHaveBeenCalledWith(PLUGIN_OVERLAY_RENDERER_ERROR, thrownError);
    expect(goodOverlay).toHaveBeenCalledOnce();
  });

  it('returns a no-op renderer when no plugin host is available', () => {
    const ctx = {
      canvas: { height: 180, width: 320 },
    } as CanvasRenderingContext2D;

    const { result } = renderHook(() => usePluginOverlays(undefined));

    expect(() => {
      result.current(ctx, 1.5);
    }).not.toThrow();
  });

  it('does nothing when the plugin host has no overlays', () => {
    const getOverlays = vi.fn(() => []);
    const pluginHost = {
      getOverlays,
    } as unknown as NonNullable<Parameters<typeof usePluginOverlays>[0]>;
    const ctx = {
      canvas: { height: 180, width: 320 },
    } as CanvasRenderingContext2D;

    const { result } = renderHook(() => usePluginOverlays(pluginHost));

    expect(() => {
      result.current(ctx, 2.5);
    }).not.toThrow();
    expect(getOverlays).toHaveBeenCalledOnce();
  });

  it('renders each plugin overlay with the canvas dimensions', () => {
    const overlay = vi.fn();
    const pluginHost = {
      getOverlays: () => [{ fn: overlay }],
    } as unknown as NonNullable<Parameters<typeof usePluginOverlays>[0]>;
    const ctx = {
      canvas: { height: 180, width: 320 },
    } as CanvasRenderingContext2D;

    const { result } = renderHook(() => usePluginOverlays(pluginHost));

    result.current(ctx, 2.5);

    expect(overlay).toHaveBeenCalledWith({
      ctx,
      globalScale: 2.5,
      height: 180,
      width: 320,
    });
  });

  it('logs overlay errors and keeps processing', () => {
    const consoleError = vi.spyOn(console, 'error').mockImplementation(() => {});
    const goodOverlay = vi.fn();
    const thrownError = new Error('boom');
    const pluginHost = {
      getOverlays: () => [
        { fn: () => { throw thrownError; } },
        { fn: goodOverlay },
      ],
    } as unknown as NonNullable<Parameters<typeof usePluginOverlays>[0]>;

    const { result } = renderHook(() => usePluginOverlays(pluginHost));

    result.current({ canvas: { height: 90, width: 120 } } as CanvasRenderingContext2D, 1);

    expect(consoleError).toHaveBeenCalledOnce();
    expect(consoleError).toHaveBeenCalledWith(PLUGIN_OVERLAY_RENDERER_ERROR, thrownError);
    expect(goodOverlay).toHaveBeenCalledOnce();
    consoleError.mockRestore();
  });

  it('uses the latest plugin host after rerender', () => {
    const firstOverlay = vi.fn();
    const secondOverlay = vi.fn();
    const ctx = {
      canvas: { height: 90, width: 120 },
    } as CanvasRenderingContext2D;
    const { result, rerender } = renderHook(
      ({ pluginHost }: { pluginHost?: Parameters<typeof usePluginOverlays>[0] }) =>
        usePluginOverlays(pluginHost),
      {
        initialProps: {
          pluginHost: {
            getOverlays: () => [{ fn: firstOverlay }],
          } as unknown as NonNullable<Parameters<typeof usePluginOverlays>[0]>,
        },
      },
    );

    act(() => {
      result.current(ctx, 1);
    });

    rerender({
      pluginHost: {
        getOverlays: () => [{ fn: secondOverlay }],
      } as unknown as NonNullable<Parameters<typeof usePluginOverlays>[0]>,
    });

    act(() => {
      result.current(ctx, 2);
    });

    expect(firstOverlay).toHaveBeenCalledOnce();
    expect(secondOverlay).toHaveBeenCalledOnce();
    expect(secondOverlay).toHaveBeenCalledWith({
      ctx,
      globalScale: 2,
      height: 90,
      width: 120,
    });
  });
});

import { renderHook } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import type { IPhysicsSettings } from '../../../../../../src/shared/settings/physics';

const physicsHarness = vi.hoisted(() => ({
  initPhysics: vi.fn(),
  resolvePhysicsInitAction: vi.fn(),
  syncPhysicsAnimation: vi.fn(),
}));

vi.mock('../../../../../../src/webview/components/graph/runtime/physics', () => ({
  initPhysics: physicsHarness.initPhysics,
  syncPhysicsAnimation: physicsHarness.syncPhysicsAnimation,
}));

vi.mock('../../../../../../src/webview/components/graph/runtime/physicsLifecycle', () => ({
  resolvePhysicsInitAction: physicsHarness.resolvePhysicsInitAction,
}));

import { usePhysicsRuntimeInit } from '../../../../../../src/webview/components/graph/runtime/use/graph/init';

const SETTINGS: IPhysicsSettings = {
  centerForce: 0.1,
  damping: 0.7,
  linkDistance: 120,
  linkForce: 0.4,
  repelForce: 500,
};

function createGraph() {
  return {} as Parameters<typeof usePhysicsRuntimeInit>[0]['fg2dRef']['current'];
}

describe('webview/graph/runtime/use/graph/init', () => {
  beforeEach(() => {
    physicsHarness.initPhysics.mockReset();
    physicsHarness.resolvePhysicsInitAction.mockReset();
    physicsHarness.syncPhysicsAnimation.mockReset();
  });

  it('defers the first 3d init by two frames and then initializes the graph', () => {
    const graph = createGraph();
    const frames: FrameRequestCallback[] = [];

    vi.stubGlobal('requestAnimationFrame', vi.fn((callback: FrameRequestCallback) => {
      frames.push(callback);
      return frames.length;
    }));
    vi.stubGlobal('cancelAnimationFrame', vi.fn());

    physicsHarness.resolvePhysicsInitAction.mockReturnValue({
      instance: graph,
      type: 'init',
    });

    renderHook(() => usePhysicsRuntimeInit({
      fg2dRef: { current: undefined },
      fg3dRef: { current: graph },
      graphMode: '3d',
      physicsInitialisedRef: { current: false },
      physicsPaused: true,
      physicsSettingsRef: { current: SETTINGS },
      pendingThreeDimensionalInitRef: { current: true },
      previousPhysicsRef: { current: null },
    }));

    expect(physicsHarness.initPhysics).not.toHaveBeenCalled();
    expect(frames).toHaveLength(1);

    frames.shift()?.(0);

    expect(physicsHarness.initPhysics).not.toHaveBeenCalled();
    expect(frames).toHaveLength(1);

    frames.shift()?.(0);

    expect(physicsHarness.initPhysics).toHaveBeenCalledWith(graph, SETTINGS);
    expect(physicsHarness.syncPhysicsAnimation).toHaveBeenCalledWith(graph, true);
  });

  it('initializes immediately in 2d mode and stores the current physics settings', () => {
    const graph = createGraph();
    const requestAnimationFrame = vi.fn();
    const cancelAnimationFrame = vi.fn();

    vi.stubGlobal('requestAnimationFrame', requestAnimationFrame);
    vi.stubGlobal('cancelAnimationFrame', cancelAnimationFrame);

    physicsHarness.resolvePhysicsInitAction.mockReturnValue({
      instance: graph,
      type: 'init',
    });

    const physicsInitialisedRef = { current: false };
    const physicsSettingsRef = { current: SETTINGS };
    const previousPhysicsRef = { current: null as IPhysicsSettings | null };

    const { unmount } = renderHook(() => usePhysicsRuntimeInit({
      fg2dRef: { current: graph },
      fg3dRef: { current: undefined },
      graphMode: '2d',
      physicsInitialisedRef,
      physicsPaused: false,
      physicsSettingsRef,
      pendingThreeDimensionalInitRef: { current: false },
      previousPhysicsRef,
    }));

    expect(physicsHarness.resolvePhysicsInitAction).toHaveBeenCalledWith({
      fg2d: graph,
      fg3d: undefined,
      graphMode: '2d',
      physicsInitialised: false,
    });
    expect(physicsHarness.initPhysics).toHaveBeenCalledWith(graph, SETTINGS);
    expect(physicsHarness.syncPhysicsAnimation).not.toHaveBeenCalled();
    expect(previousPhysicsRef.current).toEqual(SETTINGS);
    expect(previousPhysicsRef.current).not.toBe(SETTINGS);
    expect(physicsInitialisedRef.current).toBe(true);
    expect(requestAnimationFrame).not.toHaveBeenCalled();

    unmount();

    expect(cancelAnimationFrame).not.toHaveBeenCalled();
  });

  it('skips initialization work when the lifecycle says to wait', () => {
    const requestAnimationFrame = vi.fn();
    vi.stubGlobal('requestAnimationFrame', requestAnimationFrame);
    vi.stubGlobal('cancelAnimationFrame', vi.fn());

    physicsHarness.resolvePhysicsInitAction.mockReturnValue({ type: 'skip' });

    renderHook(() => usePhysicsRuntimeInit({
      fg2dRef: { current: undefined },
      fg3dRef: { current: undefined },
      graphMode: '2d',
      physicsInitialisedRef: { current: false },
      physicsPaused: false,
      physicsSettingsRef: { current: SETTINGS },
      pendingThreeDimensionalInitRef: { current: false },
      previousPhysicsRef: { current: null },
    }));

    expect(physicsHarness.initPhysics).not.toHaveBeenCalled();
    expect(physicsHarness.syncPhysicsAnimation).not.toHaveBeenCalled();
    expect(requestAnimationFrame).not.toHaveBeenCalled();
    expect(physicsHarness.resolvePhysicsInitAction).toHaveBeenCalledWith({
      fg2d: undefined,
      fg3d: undefined,
      graphMode: '2d',
      physicsInitialised: false,
    });
  });

  it('cancels a pending retry on cleanup', () => {
    const cancelAnimationFrame = vi.fn();

    vi.stubGlobal('requestAnimationFrame', vi.fn(() => 42));
    vi.stubGlobal('cancelAnimationFrame', cancelAnimationFrame);
    physicsHarness.resolvePhysicsInitAction.mockReturnValue({ type: 'wait' });

    const { unmount } = renderHook(() => usePhysicsRuntimeInit({
      fg2dRef: { current: undefined },
      fg3dRef: { current: undefined },
      graphMode: '2d',
      physicsInitialisedRef: { current: false },
      physicsPaused: false,
      physicsSettingsRef: { current: SETTINGS },
      pendingThreeDimensionalInitRef: { current: false },
      previousPhysicsRef: { current: null },
    }));

    unmount();

    expect(cancelAnimationFrame).toHaveBeenCalledWith(42);
  });
});

import { renderHook } from '@testing-library/react';
import * as THREE from 'three';
import { describe, expect, it } from 'vitest';
import type { FGNode } from '../../../../src/webview/components/graph/model/build';
import {
  findGraphNodeById,
  getMeshHighlightVisuals,
  isMeshNodeHighlighted,
  updateMeshHighlights,
  useMeshHighlights,
} from '../../../../src/webview/components/graph/runtime/use/directional/meshHighlights';

function createMesh(color: string): THREE.Mesh {
  return new THREE.Mesh(
    new THREE.SphereGeometry(1, 4, 4),
    new THREE.MeshLambertMaterial({ color, transparent: true }),
  );
}

function getHexString(material: THREE.MeshLambertMaterial): string {
  return (material.color as THREE.Color & { getHexString(): string }).getHexString();
}

function createNodes(): FGNode[] {
  return [
    { color: '#112233', id: 'selected' } as FGNode,
    { color: '#445566', id: 'neighbor' } as FGNode,
    { color: '#778899', id: 'other' } as FGNode,
  ];
}

describe('graph/runtime/useMeshHighlights', () => {
  it('findGraphNodeById returns the matching graph node by id', () => {
    const nodes = createNodes();

    expect(findGraphNodeById(nodes, 'neighbor')).toBe(nodes[1]);
  });

  it('findGraphNodeById returns undefined when no graph node matches', () => {
    expect(findGraphNodeById(createNodes(), 'missing')).toBeUndefined();
  });

  it('isMeshNodeHighlighted keeps all nodes highlighted when no node is focused', () => {
    expect(isMeshNodeHighlighted({
      highlighted: null,
      highlightedNeighbors: new Set(['neighbor']),
      nodeId: 'other',
    })).toBe(true);
  });

  it('isMeshNodeHighlighted returns true for the focused node and its neighbors', () => {
    expect(isMeshNodeHighlighted({
      highlighted: 'selected',
      highlightedNeighbors: new Set(['neighbor']),
      nodeId: 'selected',
    })).toBe(true);

    expect(isMeshNodeHighlighted({
      highlighted: 'selected',
      highlightedNeighbors: new Set(['neighbor']),
      nodeId: 'neighbor',
    })).toBe(true);
  });

  it('isMeshNodeHighlighted returns false for unrelated nodes while focused', () => {
    expect(isMeshNodeHighlighted({
      highlighted: 'selected',
      highlightedNeighbors: new Set(['neighbor']),
      nodeId: 'other',
    })).toBe(false);
  });

  it('getMeshHighlightVisuals dims unhighlighted nodes', () => {
    expect(getMeshHighlightVisuals({
      isHighlighted: false,
      isSelected: false,
      nodeColor: '#112233',
    })).toEqual({
      color: '#646464',
      opacity: 0.3,
    });
  });

  it('getMeshHighlightVisuals keeps the node color for highlighted non-selected nodes', () => {
    expect(getMeshHighlightVisuals({
      isHighlighted: true,
      isSelected: false,
      nodeColor: '#112233',
    })).toEqual({
      color: '#112233',
      opacity: 1,
    });
  });

  it('getMeshHighlightVisuals brightens highlighted selected nodes', () => {
    expect(getMeshHighlightVisuals({
      isHighlighted: true,
      isSelected: true,
      nodeColor: '#112233',
    })).toEqual({
      color: '#ffffff',
      opacity: 1,
    });
  });

  it('updateMeshHighlights skips meshes whose graph node is missing', () => {
    const unknownMesh = createMesh('#abcdef');

    updateMeshHighlights({
      graphNodes: createNodes(),
      highlighted: 'selected',
      highlightedNeighbors: new Set(['neighbor']),
      meshes: new Map([['missing', unknownMesh]]),
      selectedNodeIds: new Set(['selected']),
    });

    const material = unknownMesh.material as THREE.MeshLambertMaterial;
    expect(getHexString(material)).toBe('abcdef');
    expect(material.opacity).toBe(1);
  });

  it('updateMeshHighlights dims unrelated meshes and brightens selected ones', () => {
    const selectedMesh = createMesh('#123456');
    const neighborMesh = createMesh('#aaaaaa');
    const dimmedMesh = createMesh('#abcdef');

    updateMeshHighlights({
      graphNodes: createNodes(),
      highlighted: 'selected',
      highlightedNeighbors: new Set(['neighbor']),
      meshes: new Map([
        ['selected', selectedMesh],
        ['neighbor', neighborMesh],
        ['other', dimmedMesh],
      ]),
      selectedNodeIds: new Set(['selected']),
    });

    const selectedMaterial = selectedMesh.material as THREE.MeshLambertMaterial;
    const neighborMaterial = neighborMesh.material as THREE.MeshLambertMaterial;
    const dimmedMaterial = dimmedMesh.material as THREE.MeshLambertMaterial;

    expect(getHexString(selectedMaterial)).toBe('ffffff');
    expect(selectedMaterial.opacity).toBe(1);
    expect(getHexString(neighborMaterial)).toBe('445566');
    expect(neighborMaterial.opacity).toBe(1);
    expect(getHexString(dimmedMaterial)).toBe('646464');
    expect(dimmedMaterial.opacity).toBe(0.3);
  });

  it('reruns highlight updates when highlightVersion changes across rerender', () => {
    const selectedMesh = createMesh('#123456');
    const neighborMesh = createMesh('#abcdef');
    const highlightedNodeRef = { current: 'selected' };
    const highlightedNeighborsRef = { current: new Set(['neighbor']) };
    const selectedNodesSetRef = { current: new Set(['selected']) };
    const graphDataRef = {
      current: {
        links: [],
        nodes: createNodes(),
      },
    };
    const meshesRef = {
      current: new Map([
        ['selected', selectedMesh],
        ['neighbor', neighborMesh],
      ]),
    };
    const { rerender } = renderHook(
      ({ highlightVersion }: { highlightVersion: number }) => useMeshHighlights({
        graphDataRef,
        highlightVersion,
        highlightedNeighborsRef,
        highlightedNodeRef,
        meshesRef,
        selectedNodesSetRef,
      }),
      {
        initialProps: { highlightVersion: 1 },
      },
    );

    expect(getHexString(selectedMesh.material as THREE.MeshLambertMaterial)).toBe('ffffff');
    expect(getHexString(neighborMesh.material as THREE.MeshLambertMaterial)).toBe('445566');

    highlightedNodeRef.current = 'neighbor';
    highlightedNeighborsRef.current = new Set();
    selectedNodesSetRef.current = new Set(['neighbor']);

    rerender({ highlightVersion: 2 });

    expect(getHexString(selectedMesh.material as THREE.MeshLambertMaterial)).toBe('646464');
    expect((selectedMesh.material as THREE.MeshLambertMaterial).opacity).toBe(0.3);
    expect(getHexString(neighborMesh.material as THREE.MeshLambertMaterial)).toBe('ffffff');
    expect((neighborMesh.material as THREE.MeshLambertMaterial).opacity).toBe(1);
  });
});

