    expect(ctx.font).toBe('bold 12px sans-serif');
    expect(ctx.fillStyle).toBe('#eeeeee');
    expect(ctx.roundRect).toHaveBeenCalledWith(10 - 15, 20 - 9, 30, 18, 9);
