    expect(ctx.font).toBe('10px sans-serif');
    expect(ctx.fillStyle).toBe('#FFFFFF');
    expect(ctx.textAlign).toBe('center');
    expect(ctx.textBaseline).toBe('middle');
    expect(ctx.fillText).toHaveBeenCalledWith('File.ts', 8, 12);
  });
});

