		graphContextSelection: { kind: 'background', targets: [] },
		imageCacheVersion: 0,
		nodeDecorationsRef: { current: {} },
		nodeSizeModeRef: { current: 'connections' },
		setContextSelection: vi.fn(),
		setHighlightVersion: vi.fn(),
		setSelectedNodes: vi.fn(),
