import { act, renderHook } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import type { IPhysicsSettings } from '../../../../src/shared/settings/physics';

const runtimeHarness = vi.hoisted(() => ({
  applyPhysicsSettings: vi.fn(),
  initPhysics: vi.fn(),
  resolvePhysicsInitAction: vi.fn(),
  selectActivePhysicsGraph: vi.fn(),
  shouldApplyPhysicsUpdate: vi.fn(),
  syncPhysicsAnimation: vi.fn(),
}));

vi.mock('../../../../src/webview/components/graph/runtime/physics', () => ({
  applyPhysicsSettings: runtimeHarness.applyPhysicsSettings,
  initPhysics: runtimeHarness.initPhysics,
  syncPhysicsAnimation: runtimeHarness.syncPhysicsAnimation,
}));

vi.mock('../../../../src/webview/components/graph/runtime/physicsLifecycle', () => ({
  resolvePhysicsInitAction: runtimeHarness.resolvePhysicsInitAction,
  selectActivePhysicsGraph: runtimeHarness.selectActivePhysicsGraph,
  shouldApplyPhysicsUpdate: runtimeHarness.shouldApplyPhysicsUpdate,
}));

import { usePhysicsRuntime } from '../../../../src/webview/components/graph/runtime/use/graph/physics';

const SETTINGS: IPhysicsSettings = {
  centerForce: 0.1,
  damping: 0.7,
  linkDistance: 120,
  linkForce: 0.4,
  repelForce: 500,
};

type UsePhysicsRuntimeOptions = Parameters<typeof usePhysicsRuntime>[0];
type Graph2DCurrent = UsePhysicsRuntimeOptions['fg2dRef']['current'];

function create2DGraph(): Graph2DCurrent {
  return {} as Graph2DCurrent;
}

describe('webview/graph/runtime/usePhysicsRuntime control flow', () => {
  beforeEach(() => {
    runtimeHarness.applyPhysicsSettings.mockReset();
    runtimeHarness.initPhysics.mockReset();
    runtimeHarness.resolvePhysicsInitAction.mockReset();
    runtimeHarness.selectActivePhysicsGraph.mockReset();
    runtimeHarness.shouldApplyPhysicsUpdate.mockReset();
    runtimeHarness.selectActivePhysicsGraph.mockReturnValue(create2DGraph());
    runtimeHarness.shouldApplyPhysicsUpdate.mockReturnValue(false);
  });

  it('waits and retries until the init helper returns an instance', () => {
    const frames: FrameRequestCallback[] = [];
    const requestAnimationFrame = vi.fn((callback: FrameRequestCallback) => {
      frames.push(callback);
      return frames.length;
    });

    vi.stubGlobal('requestAnimationFrame', requestAnimationFrame);
    vi.stubGlobal('cancelAnimationFrame', vi.fn());

    const graph = create2DGraph();
    const updatedSettings = {
      ...SETTINGS,
      damping: SETTINGS.damping + 0.1,
    };

    let resolveCalls = 0;
    runtimeHarness.resolvePhysicsInitAction.mockImplementation(() => {
      resolveCalls += 1;
      return resolveCalls === 1
        ? { type: 'wait' }
        : { instance: graph, type: 'init' };
    });

    const { rerender } = renderHook(
      ({ physicsSettings }) => usePhysicsRuntime({
        fg2dRef: { current: graph },
        fg3dRef: { current: undefined },
        graphMode: '2d',
        layoutKey: 'layout:a',
        physicsSettings,
      }),
      { initialProps: { physicsSettings: SETTINGS } },
    );

    expect(runtimeHarness.resolvePhysicsInitAction).toHaveBeenCalledWith({
      fg2d: graph,
      fg3d: undefined,
      graphMode: '2d',
      physicsInitialised: false,
    });
    expect(requestAnimationFrame).toHaveBeenCalled();

    rerender({ physicsSettings: updatedSettings });

    act(() => {
      frames.shift()?.(0);
    });

    expect(runtimeHarness.resolvePhysicsInitAction.mock.calls.length).toBeGreaterThanOrEqual(2);
    expect(runtimeHarness.initPhysics).toHaveBeenCalled();
    expect(runtimeHarness.initPhysics.mock.calls.at(-1)).toEqual([graph, updatedSettings]);
  });

  it('skips retrying when physics initialization is already complete', () => {
    const requestAnimationFrame = vi.fn();

    vi.stubGlobal('requestAnimationFrame', requestAnimationFrame);
    vi.stubGlobal('cancelAnimationFrame', vi.fn());

    runtimeHarness.resolvePhysicsInitAction.mockReturnValue({ type: 'skip' });

    renderHook(() => usePhysicsRuntime({
      fg2dRef: { current: create2DGraph() },
      fg3dRef: { current: undefined },
      graphMode: '2d',
      layoutKey: 'layout:a',
      physicsSettings: SETTINGS,
    }));

    expect(runtimeHarness.resolvePhysicsInitAction).toHaveBeenCalledWith({
      fg2d: expect.any(Object),
      fg3d: undefined,
      graphMode: '2d',
      physicsInitialised: false,
    });
    expect(requestAnimationFrame).not.toHaveBeenCalled();
    expect(runtimeHarness.initPhysics).not.toHaveBeenCalled();
  });

  it('does not sync animation before initialization finishes for a newly selected graph mode', () => {
    const graph = create2DGraph();
    const frames: FrameRequestCallback[] = [];

    vi.stubGlobal('requestAnimationFrame', vi.fn((callback: FrameRequestCallback) => {
      frames.push(callback);
      return frames.length;
    }));
    vi.stubGlobal('cancelAnimationFrame', vi.fn());

    runtimeHarness.selectActivePhysicsGraph.mockReturnValue(graph);

    let resolveCalls = 0;
    runtimeHarness.resolvePhysicsInitAction.mockImplementation(() => {
      resolveCalls += 1;
      return resolveCalls === 1
        ? { type: 'wait' }
        : { instance: graph, type: 'init' };
    });

    renderHook(() => usePhysicsRuntime({
      fg2dRef: { current: undefined },
      fg3dRef: { current: graph },
      graphMode: '3d',
      layoutKey: 'layout:a',
      physicsPaused: false,
      physicsSettings: SETTINGS,
    }));

    expect(runtimeHarness.syncPhysicsAnimation).not.toHaveBeenCalled();

    act(() => {
      frames.shift()?.(0);
    });

    expect(runtimeHarness.initPhysics).not.toHaveBeenCalled();
    expect(runtimeHarness.syncPhysicsAnimation).not.toHaveBeenCalled();

    act(() => {
      frames.shift()?.(0);
    });

    expect(runtimeHarness.initPhysics).not.toHaveBeenCalled();
    expect(runtimeHarness.syncPhysicsAnimation).not.toHaveBeenCalled();

    act(() => {
      frames.shift()?.(0);
    });

    expect(runtimeHarness.initPhysics).toHaveBeenCalledWith(graph, SETTINGS);
    expect(runtimeHarness.syncPhysicsAnimation).not.toHaveBeenCalled();
  });
});

import { renderHook } from '@testing-library/react';
import { describe, expect, it } from 'vitest';
import type { IGraphData } from '../../../../src/shared/graph/types';
import type { NodeSizeMode } from '../../../../src/shared/settings/modes';
import {
  DEFAULT_NODE_SIZE,
  FAVORITE_BORDER_COLOR,
  getDepthSizeMultiplier,
  type FGNode,
} from '../../../../src/webview/components/graph/model/build';
import {
  applyNodeAppearance,
  useNodeAppearance,
} from '../../../../src/webview/components/graph/runtime/use/directional/nodeAppearance';
import { adjustColorForLightTheme } from '../../../../src/webview/theme/useTheme';

function createData(nodes: IGraphData['nodes']): IGraphData {
    return {
      edges: nodes.length > 1
      ? nodes.slice(1).map((node) => ({ id: `${nodes[0].id}->${node.id}`, from: nodes[0].id, to: node.id , kind: 'import', sources: [] }))
      : [],
      nodes,
    };
}

function createGraphNode(id: string, overrides: Partial<FGNode> = {}): FGNode {
  return {
    baseOpacity: 1,
    borderColor: '#000000',
    borderWidth: 0,
    color: '#000000',
    id,
    isFavorite: false,
    label: id,
    size: 0,
    ...overrides,
  } as FGNode;
}

describe('graph/runtime/useNodeAppearance', () => {
  describe('applyNodeAppearance', () => {
    it('applies exact size, color, and border styling for focused, favorite, and regular nodes', () => {
      const graphNodes = [
        createGraphNode('root'),
        createGraphNode('favorite'),
        createGraphNode('regular'),
      ];

      applyNodeAppearance({
        data: createData([
          { color: '#112233', depthLevel: 0, id: 'root', label: 'Root' },
          { color: '#445566', depthLevel: 2, id: 'favorite', label: 'Favorite' },
          { color: '#778899', depthLevel: 1, id: 'regular', label: 'Regular' },
        ]),
        favorites: new Set(['favorite']),
        graphNodes,
        nodeSizeMode: 'uniform',
        theme: 'dark',
      });

      expect(graphNodes[0]).toMatchObject({
        borderColor: '#60a5fa',
        borderWidth: 4,
        color: '#112233',
        isFavorite: false,
        size: DEFAULT_NODE_SIZE * getDepthSizeMultiplier(0),
      });
      expect(graphNodes[1]).toMatchObject({
        borderColor: FAVORITE_BORDER_COLOR,
        borderWidth: 3,
        color: '#445566',
        isFavorite: true,
        size: DEFAULT_NODE_SIZE * getDepthSizeMultiplier(2),
      });
      expect(graphNodes[2]).toMatchObject({
        borderColor: '#778899',
        borderWidth: 2,
        color: '#778899',
        isFavorite: false,
        size: DEFAULT_NODE_SIZE * getDepthSizeMultiplier(1),
      });
    });

    it('adjusts node colors for the light theme and uses the light focused border color', () => {
      const graphNodes = [
        createGraphNode('root'),
        createGraphNode('regular'),
      ];
      const rootColor = '#112233';
      const regularColor = '#445566';

      applyNodeAppearance({
        data: createData([
          { color: rootColor, depthLevel: 0, id: 'root', label: 'Root' },
          { color: regularColor, depthLevel: 1, id: 'regular', label: 'Regular' },
        ]),
        favorites: new Set<string>(),
        graphNodes,
        nodeSizeMode: 'uniform',
        theme: 'light',
      });

      expect(graphNodes[0]).toMatchObject({
        borderColor: '#2563eb',
        color: adjustColorForLightTheme(rootColor),
      });
      expect(graphNodes[1]).toMatchObject({
        borderColor: adjustColorForLightTheme(regularColor),
        color: adjustColorForLightTheme(regularColor),
      });
    });

    it('leaves graph nodes unchanged when they are not present in the backing graph data', () => {
      const knownNode = createGraphNode('known');
      const missingNode = createGraphNode('missing', {
        borderColor: '#abcdef',
        borderWidth: 7,
        color: '#fedcba',
        isFavorite: true,
        size: 99,
      });

      expect(() => applyNodeAppearance({
        data: createData([
          { color: '#112233', depthLevel: 1, id: 'known', label: 'Known' },
        ]),
        favorites: new Set<string>(),
        graphNodes: [knownNode, missingNode],
        nodeSizeMode: 'uniform',
        theme: 'dark',
      })).not.toThrow();

      expect(knownNode).toMatchObject({
        borderColor: '#112233',
        borderWidth: 2,
        color: '#112233',
        isFavorite: false,
        size: DEFAULT_NODE_SIZE * getDepthSizeMultiplier(1),
      });
      expect(missingNode).toMatchObject({
        borderColor: '#abcdef',
        borderWidth: 7,
        color: '#fedcba',
        isFavorite: true,
        size: 99,
      });
    });

    it('keeps nodes without a depth level unfocused when applying appearance', () => {
      const graphNodes = [createGraphNode('root')];

      applyNodeAppearance({
        data: createData([
          { color: '#112233', id: 'root', label: 'Root' },
        ]),
        favorites: new Set<string>(),
        graphNodes,
        nodeSizeMode: 'uniform',
        theme: 'dark',
      });

      expect(graphNodes[0]).toMatchObject({
        borderColor: '#112233',
        borderWidth: 2,
        color: '#112233',
        isFavorite: false,
        size: DEFAULT_NODE_SIZE * getDepthSizeMultiplier(undefined),
      });
    });
  });

  describe('useNodeAppearance', () => {
    it('reapplies appearance when the theme changes on rerender', () => {
      const graphNodes = [createGraphNode('root')];
      const dataRef = {
        current: createData([
          { color: '#112233', depthLevel: 0, id: 'root', label: 'Root' },
        ]),
      };
      const graphDataRef = { current: { links: [], nodes: graphNodes } };
      const favorites = new Set<string>();

      const { rerender } = renderHook(
        (theme: 'dark' | 'light') => useNodeAppearance({
          dataRef,
          favorites,
          graphDataRef,
          nodeSizeMode: 'uniform',
          theme,
        }),
        {
          initialProps: 'dark',
        },
      );

      expect(graphNodes[0]).toMatchObject({
        borderColor: '#60a5fa',
        color: '#112233',
      });

      rerender('light');

      expect(graphNodes[0]).toMatchObject({
        borderColor: '#2563eb',
        color: adjustColorForLightTheme('#112233'),
      });
    });

    it('does not introduce focused borders for nodes without a depth level when node size mode changes', () => {
      const graphNodes = [createGraphNode('root')];
      const dataRef = {
        current: createData([
          { color: '#112233', id: 'root', label: 'Root' },
        ]),
      };
      const graphDataRef = { current: { links: [], nodes: graphNodes } };
      const favorites = new Set<string>();

      const { rerender } = renderHook(
        ({ nodeSizeMode }: { nodeSizeMode: NodeSizeMode }) => useNodeAppearance({
          dataRef,
          favorites,
          graphDataRef,
          nodeSizeMode,
          theme: 'dark',
        }),
        {
          initialProps: { nodeSizeMode: 'uniform' as NodeSizeMode },
        },
      );

      expect(graphNodes[0]).toMatchObject({
        borderColor: '#112233',
        borderWidth: 2,
        size: DEFAULT_NODE_SIZE,
      });

      rerender({ nodeSizeMode: 'connections' as NodeSizeMode });

      expect(graphNodes[0]).toMatchObject({
        borderColor: '#112233',
        borderWidth: 2,
      });
    });
  });
});

import { renderHook } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { usePhysicsRuntimePause } from '../../../../../../src/webview/components/graph/runtime/use/graph/pause';

const physicsHarness = vi.hoisted(() => ({
  selectActivePhysicsGraph: vi.fn(),
  syncPhysicsAnimation: vi.fn(),
}));

vi.mock('../../../../../../src/webview/components/graph/runtime/physicsLifecycle', () => ({
  selectActivePhysicsGraph: physicsHarness.selectActivePhysicsGraph,
}));

vi.mock('../../../../../../src/webview/components/graph/runtime/physics', () => ({
  syncPhysicsAnimation: physicsHarness.syncPhysicsAnimation,
}));

describe('webview/graph/runtime/use/graph/pause', () => {
  beforeEach(() => {
    physicsHarness.selectActivePhysicsGraph.mockReset();
    physicsHarness.syncPhysicsAnimation.mockReset();
  });

  it('syncs the active graph when physics pause changes', () => {
    const graph = {} as never;
    physicsHarness.selectActivePhysicsGraph.mockReturnValue(graph);

    const { rerender } = renderHook(
      ({ physicsPaused }: { physicsPaused: boolean }) => usePhysicsRuntimePause({
        fg2dRef: { current: graph },
        fg3dRef: { current: undefined },
        graphMode: '2d',
        physicsInitialisedRef: { current: true },
        physicsPaused,
      }),
      { initialProps: { physicsPaused: false } },
    );

    rerender({ physicsPaused: true });

    expect(physicsHarness.syncPhysicsAnimation).toHaveBeenCalledWith(graph, true);
  });

  it('does not sync before initialization completes', () => {
    physicsHarness.selectActivePhysicsGraph.mockReturnValue(undefined);

    renderHook(() => usePhysicsRuntimePause({
      fg2dRef: { current: undefined },
      fg3dRef: { current: undefined },
      graphMode: '2d',
      physicsInitialisedRef: { current: false },
      physicsPaused: true,
    }));

    expect(physicsHarness.syncPhysicsAnimation).not.toHaveBeenCalled();
  });

  it('does not sync when the active graph exists but initialization has not completed', () => {
    const graph = {} as never;
    physicsHarness.selectActivePhysicsGraph.mockReturnValue(graph);

    renderHook(() => usePhysicsRuntimePause({
      fg2dRef: { current: graph },
      fg3dRef: { current: undefined },
      graphMode: '2d',
      physicsInitialisedRef: { current: false },
      physicsPaused: true,
    }));

    expect(physicsHarness.syncPhysicsAnimation).not.toHaveBeenCalled();
  });
});

