import { describe, expect, it } from 'vitest';
import { getGraphWebviewMessageEffects } from '../../../../src/webview/components/graph/messages/effects';

describe('graph/messages/effects', () => {
  it('fits the view for FIT_VIEW messages', () => {
    expect(getGraphWebviewMessageEffects({
      message: { type: 'FIT_VIEW' },
      graphMode: '3d',
      tooltipPath: null,
      graphNodes: [],
    })).toEqual([{ kind: 'fitView' }]);
  });

  it('zooms only in 2d mode for zoom messages', () => {
    expect(getGraphWebviewMessageEffects({
      message: { type: 'ZOOM_IN' },
      graphMode: '2d',
      tooltipPath: null,
      graphNodes: [],
    })).toEqual([{ kind: 'zoom', factor: 1.2 }]);

    expect(getGraphWebviewMessageEffects({
      message: { type: 'ZOOM_OUT' },
      graphMode: '2d',
      tooltipPath: null,
      graphNodes: [],
    })).toEqual([{ kind: 'zoom', factor: 1 / 1.2 }]);

    expect(getGraphWebviewMessageEffects({
      message: { type: 'ZOOM_IN' },
      graphMode: '3d',
      tooltipPath: null,
      graphNodes: [],
    })).toEqual([]);

    expect(getGraphWebviewMessageEffects({
      message: { type: 'ZOOM_OUT' },
      graphMode: '3d',
      tooltipPath: null,
      graphNodes: [],
    })).toEqual([]);
  });

  it('caches file info and updates the tooltip when the paths match', () => {
    expect(getGraphWebviewMessageEffects({
      message: {
        type: 'FILE_INFO',
        payload: {
          path: 'src/app.ts',
          size: 123,
          lastModified: 1704067200000,
          incomingCount: 2,
          outgoingCount: 3,
          visits: 4,
        },
      },
      graphMode: '2d',
      tooltipPath: 'src/app.ts',
      graphNodes: [],
    })).toEqual([
      {
        kind: 'cacheFileInfo',
        info: {
          path: 'src/app.ts',
          size: 123,
          lastModified: 1704067200000,
          incomingCount: 2,
          outgoingCount: 3,
          visits: 4,
        },
      },
      {
        kind: 'updateTooltipInfo',
        info: {
          path: 'src/app.ts',
          size: 123,
          lastModified: 1704067200000,
          incomingCount: 2,
          outgoingCount: 3,
          visits: 4,
        },
      },
    ]);
  });

  it('returns only the cache update when file info targets a different tooltip path', () => {
    expect(getGraphWebviewMessageEffects({
      message: {
        type: 'FILE_INFO',
        payload: {
          path: 'src/app.ts',
          size: 123,
          lastModified: 1704067200000,
          incomingCount: 2,
          outgoingCount: 3,
          visits: 4,
        },
      },
      graphMode: '2d',
      tooltipPath: 'src/utils.ts',
      graphNodes: [],
