      {
        kind: 'cacheFileInfo',
        info: {
          path: 'src/app.ts',
          size: 123,
          lastModified: 1704067200000,
          incomingCount: 2,
          outgoingCount: 3,
          visits: 4,
        },
      },
    ]);
