  it('updates cached node access counts', () => {
    expect(getGraphWebviewMessageEffects({
      message: { type: 'NODE_ACCESS_COUNT_UPDATED', payload: { nodeId: 'src/app.ts', accessCount: 7 } },
      graphMode: '2d',
