import { describe, expect, it } from 'vitest';
import { getGraphKeyboardCommand } from '../../../../src/webview/components/graph/keyboard/effects';

describe('graph/keyboard/effects', () => {
  it('ignores shortcuts when focus is inside an editable input', () => {
    expect(getGraphKeyboardCommand({
      key: '0',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: true,
    })).toBeNull();
  });

  it('fits the view for the 0 shortcut', () => {
    expect(getGraphKeyboardCommand({
      key: '0',
      isMod: false,
      shiftKey: false,
      graphMode: '3d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'fitView' }],
    });
  });

  it('clears the selection for Escape', () => {
    expect(getGraphKeyboardCommand({
      key: 'Escape',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: ['src/app.ts'],
      allNodeIds: ['src/app.ts'],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'clearSelection' }],
    });
  });

  it('opens all selected nodes for Enter', () => {
    expect(getGraphKeyboardCommand({
      key: 'Enter',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: ['src/app.ts', 'src/utils.ts'],
      allNodeIds: ['src/app.ts', 'src/utils.ts'],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'openSelectedNodes', nodeIds: ['src/app.ts', 'src/utils.ts'] }],
    });
  });

  it('ignores Enter when nothing is selected', () => {
    expect(getGraphKeyboardCommand({
      key: 'Enter',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: ['src/app.ts'],
      targetIsEditable: false,
    })).toBeNull();
  });

  it('skips synthetic package nodes when opening selected nodes with Enter', () => {
    expect(getGraphKeyboardCommand({
      key: 'Enter',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: ['src/app.ts', 'pkg:fs'],
      allNodeIds: ['src/app.ts', 'pkg:fs'],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'openSelectedNodes', nodeIds: ['src/app.ts'] }],
    });
  });

  it('selects all nodes for the modifier+a shortcut', () => {
    expect(getGraphKeyboardCommand({
      key: 'a',
      isMod: true,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: ['src/app.ts', 'src/utils.ts'],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'selectAll', nodeIds: ['src/app.ts', 'src/utils.ts'] }],
    });
  });

  it('zooms in for the equals shortcut', () => {
    expect(getGraphKeyboardCommand({
      key: '=',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'zoom', factor: 1.2 }],
    });
  });

  it('zooms only in 2d mode for plus and minus shortcuts', () => {
    expect(getGraphKeyboardCommand({
      key: '+',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'zoom', factor: 1.2 }],
    });

    expect(getGraphKeyboardCommand({
      key: '-',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'zoom', factor: 1 / 1.2 }],
    });

    expect(getGraphKeyboardCommand({
      key: '+',
      isMod: false,
      shiftKey: false,
      graphMode: '3d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toBeNull();
  });

  it('ignores zoom-out when the graph is not 2d', () => {
    expect(getGraphKeyboardCommand({
      key: '-',
      isMod: false,
      shiftKey: false,
      graphMode: '3d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toBeNull();
  });

  it('maps modifier+z and modifier+y to undo and redo messages', () => {
    expect(getGraphKeyboardCommand({
      key: 'z',
      isMod: true,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
