      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: true,
      effects: [{ kind: 'postMessage', message: { type: 'REDO' } }],
    });

    expect(getGraphKeyboardCommand({
      key: 'y',
