    })).toEqual({
      preventDefault: true,
      stopPropagation: true,
      effects: [{ kind: 'postMessage', message: { type: 'REDO' } }],
    });
  });

  it('maps lowercase v to the cycle-view store message', () => {
    expect(getGraphKeyboardCommand({
      key: 'v',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'dispatchStoreMessage', message: { type: 'TOGGLE_DEPTH_MODE' } }],
    });
  });

  it('maps uppercase v to the cycle-view store message', () => {
    expect(getGraphKeyboardCommand({
      key: 'V',
      isMod: false,
      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'dispatchStoreMessage', message: { type: 'TOGGLE_DEPTH_MODE' } }],
