      shiftKey: false,
      graphMode: '2d',
      selectedNodeIds: [],
      allNodeIds: [],
      targetIsEditable: false,
    })).toEqual({
      preventDefault: true,
      stopPropagation: false,
      effects: [{ kind: 'dispatchStoreMessage', message: { type: 'CYCLE_LAYOUT' } }],
