import { describe, expect, it } from 'vitest';
import type { GraphPluginSlot } from '../../../../src/webview/pluginHost/api/contracts';
import {
  attachSlotHost,
  detachSlotHost,
  getOrCreateContainer,
  getOrCreateSlotContainer,
} from '../../../../src/webview/pluginHost/api/containers';

describe('pluginHost/api/containers', () => {
  it('creates and reuses plugin containers', () => {
    const containers = new Map<string, HTMLDivElement>();
    const first = getOrCreateContainer('plugin-a', containers);
    const second = getOrCreateContainer('plugin-a', containers);

    expect(first).toBe(second);
    expect(first.getAttribute('data-cg-plugin')).toBe('plugin-a');
    expect(first.style.display).toBe('none');
  });

  it('creates slot containers and moves them into attached hosts', () => {
    const slotContainers = new Map<string, Map<GraphPluginSlot, HTMLDivElement>>();
    const slotHosts = new Map<GraphPluginSlot, HTMLDivElement>();

    const container = getOrCreateSlotContainer('plugin-a', 'toolbar', slotContainers as never, slotHosts as never);
    const host = document.createElement('div');
    attachSlotHost('toolbar', host, slotContainers as never, slotHosts as never);

    expect(container.getAttribute('data-cg-slot')).toBe('toolbar');
    expect(host.contains(container)).toBe(true);
    expect(host.style.display).toBe('');

    detachSlotHost('toolbar', slotHosts as never);
    expect(slotHosts.has('toolbar')).toBe(false);
  });

  it('reuses an existing slot container and can attach a host after the container already exists', () => {
    const slotContainers = new Map<string, Map<GraphPluginSlot, HTMLDivElement>>();
    const slotHosts = new Map<GraphPluginSlot, HTMLDivElement>();

    const first = getOrCreateSlotContainer('plugin-a', 'toolbar', slotContainers as never, slotHosts as never);
    const second = getOrCreateSlotContainer('plugin-a', 'toolbar', slotContainers as never, slotHosts as never);
    const host = document.createElement('div');

    attachSlotHost('toolbar', host, slotContainers as never, slotHosts as never);
    getOrCreateSlotContainer('plugin-a', 'timeline-panel', slotContainers as never, slotHosts as never);

    expect(first).toBe(second);
    expect(host.contains(first)).toBe(true);
    expect(slotContainers.get('plugin-a')).toBeDefined();
  });

  it('attaches a slot host even when no matching slot container exists yet', () => {
    const slotContainers = new Map<string, Map<GraphPluginSlot, HTMLDivElement>>();
    const slotHosts = new Map<GraphPluginSlot, HTMLDivElement>();
    const host = document.createElement('div');

    slotContainers.set('plugin-a', new Map());
    attachSlotHost('toolbar', host, slotContainers as never, slotHosts as never);

    expect(host.getAttribute('data-cg-slot-host')).toBe('toolbar');
    expect(host.style.display).toBe('none');
  });

  it('creates a slot container directly inside an already attached host', () => {
    const slotContainers = new Map<string, Map<GraphPluginSlot, HTMLDivElement>>();
    const slotHosts = new Map<GraphPluginSlot, HTMLDivElement>();
    const host = document.createElement('div');

    attachSlotHost('toolbar', host, slotContainers as never, slotHosts as never);
    const container = getOrCreateSlotContainer('plugin-a', 'toolbar', slotContainers as never, slotHosts as never);

    expect(host.contains(container)).toBe(true);
    expect(host.style.display).toBe('');
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { removePluginRegistrations } from '../../../../src/webview/pluginHost/api/cleanup';
import type { GraphPluginSlot, NodeRenderFn, OverlayRenderFn, TooltipProviderFn } from '../../../../src/webview/pluginHost/api/contracts';

describe('removePluginRegistrations', () => {
  let nodeRenderers: Map<string, { pluginId: string; fn: NodeRenderFn }>;
  let overlays: Map<string, { pluginId: string; fn: OverlayRenderFn }>;
  let tooltipProviders: Array<{ pluginId: string; fn: TooltipProviderFn }>;
  let messageHandlers: Map<string, Set<(msg: { type: string; data: unknown }) => void>>;
  let containers: Map<string, HTMLDivElement>;
  let slotContainers: Map<string, Map<GraphPluginSlot, HTMLDivElement>>;
  let slotHosts: Map<GraphPluginSlot, HTMLDivElement>;

  beforeEach(() => {
    nodeRenderers = new Map();
    overlays = new Map();
    tooltipProviders = [];
    messageHandlers = new Map();
    containers = new Map();
    slotContainers = new Map();
    slotHosts = new Map();
    document.body.innerHTML = '';
  });

  it('removes node renderers belonging to the specified plugin', () => {
    const fn = (() => {}) as unknown as NodeRenderFn;
    nodeRenderers.set('.ts', { pluginId: 'target', fn });
    nodeRenderers.set('.js', { pluginId: 'other', fn });

    removePluginRegistrations('target', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(nodeRenderers.has('.ts')).toBe(false);
    expect(nodeRenderers.has('.js')).toBe(true);
  });

  it('removes overlays belonging to the specified plugin', () => {
    const fn = (() => {}) as unknown as OverlayRenderFn;
    overlays.set('target:heatmap', { pluginId: 'target', fn });
    overlays.set('other:overlay', { pluginId: 'other', fn });

    removePluginRegistrations('target', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(overlays.has('target:heatmap')).toBe(false);
    expect(overlays.has('other:overlay')).toBe(true);
  });

  it('removes tooltip providers belonging to the specified plugin', () => {
    const fn = (() => null) as unknown as TooltipProviderFn;
    tooltipProviders.push({ pluginId: 'target', fn });
    tooltipProviders.push({ pluginId: 'other', fn });
    tooltipProviders.push({ pluginId: 'target', fn });

    removePluginRegistrations('target', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(tooltipProviders).toHaveLength(1);
    expect(tooltipProviders[0].pluginId).toBe('other');
  });

  it('removes message handlers for the specified plugin', () => {
    messageHandlers.set('target', new Set());
    messageHandlers.set('other', new Set());

    removePluginRegistrations('target', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(messageHandlers.has('target')).toBe(false);
    expect(messageHandlers.has('other')).toBe(true);
  });

  it('removes and detaches the container for the specified plugin', () => {
    const container = document.createElement('div');
    document.body.appendChild(container);
    containers.set('target', container);

    removePluginRegistrations('target', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(containers.has('target')).toBe(false);
    expect(document.body.contains(container)).toBe(false);
  });

  it('handles the case when no container exists for the plugin', () => {
    // Should not throw when no container exists
    removePluginRegistrations('nonexistent', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(containers.size).toBe(0);
  });

  it('removes multiple tooltip providers for the same plugin in reverse order', () => {
    const fn1 = (() => null) as unknown as TooltipProviderFn;
    const fn2 = (() => null) as unknown as TooltipProviderFn;
    const fn3 = (() => null) as unknown as TooltipProviderFn;
    tooltipProviders.push({ pluginId: 'other', fn: fn1 });
    tooltipProviders.push({ pluginId: 'target', fn: fn2 });
    tooltipProviders.push({ pluginId: 'target', fn: fn3 });

    removePluginRegistrations('target', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(tooltipProviders).toHaveLength(1);
    expect(tooltipProviders[0].fn).toBe(fn1);
  });

  it('removes slot containers for the specified plugin and hides emptied slot hosts', () => {
    const toolbarHost = document.createElement('div');
    const toolbarContainer = document.createElement('div');
    toolbarHost.appendChild(toolbarContainer);
    slotHosts.set('toolbar', toolbarHost);
    slotContainers.set('target', new Map([['toolbar', toolbarContainer]]));

    removePluginRegistrations('target', nodeRenderers, overlays, tooltipProviders, messageHandlers, containers, slotContainers, slotHosts);

    expect(slotContainers.has('target')).toBe(false);
    expect(toolbarHost.childElementCount).toBe(0);
    expect(toolbarHost.style.display).toBe('none');
  });
});

