  it('handles FILTER_PATTERNS_UPDATED message', () => {
    store.getState().handleExtensionMessage({
      type: 'FILTER_PATTERNS_UPDATED',
      payload: { patterns: ['*.test.ts'], pluginPatterns: ['*.uid'] },
    });
