    store.getState().handleExtensionMessage({
      type: 'PHYSICS_SETTINGS_UPDATED',
      payload: physics,
    });
    expect(store.getState().physicsSettings).toEqual(physics);
  });

  it('handles DEPTH_LIMIT_UPDATED message', () => {
