  it('returns the original array when the drag indices are invalid or unchanged', () => {
    const plugins: IPluginStatus[] = [
      {
        id: 'plugin.a',
        name: 'A',
        version: '1.0.0',
        supportedExtensions: ['.a'],
        status: 'installed',
        enabled: true,
        connectionCount: 0,
      },
      {
        id: 'plugin.b',
        name: 'B',
        version: '1.0.0',
        supportedExtensions: ['.b'],
        status: 'installed',
        enabled: true,
