import { describe, expect, it } from 'vitest';
import {
  createClipboardEffects,
  createCreateFileEffects,
  createFitViewEffects,
  createFocusEffects,
  createLegendPromptEffects,
  createOpenFileEffects,
  createOptionalClipboardEffects,
